insert into products(id,name,slug,cat,subcat,img,short,descr,sort,active) values(1,'Abrochadoras Manuales','abrochadoras-manuales','construccion','abrochadoras','https://ebtools.com.ar/wp-content/uploads/2017/07/116-1024x1024.jpg','Para madera, cartón y chapas livianas.','Abrochadoras de acero tratado para uso intensivo en obras, carpintería y packaging. Diseñadas para trabajar con grapadoras J y T, garantizan un disparo limpio y preciso en cada aplicación. Ideales para quienes trabajan en volumen y necesitan velocidad sin sacrificar resultado.',1,true);
insert into products(id,name,slug,cat,subcat,img,short,descr,sort,active) values(2,'Gaviones','gaviones','construccion','contencion','https://ebtools.com.ar/wp-content/uploads/2017/12/Gavion1-1024x1024.jpg','Contención de suelos y paisajismo.','Estructuras metálicas de malla hexagonal galvanizada para contención de taludes, canales y muros de contención. Su diseño modular permite adaptarse a diferentes geometrías de terreno. Alta resistencia a la corrosión y cargas de suelo.',2,true);
insert into products(id,name,slug,cat,subcat,img,short,descr,sort,active) values(3,'Revocadoras Neumáticas','revocadoras-neumaticas','construccion','revoque','https://ebtools.com.ar/wp-content/uploads/2021/01/50-1024x1024.jpg','Proyección de mortero de alto rendimiento.','Máquinas revocadoras neumáticas para proyección de mortero, cemento y yeso en superficies interiores y exteriores. Reducen drásticamente el tiempo de aplicación frente al revoque manual. Compatibles con compresores de 2HP o más.',3,true);
insert into products(id,name,slug,cat,subcat,img,short,descr,sort,active) values(4,'Abrochadoras Neumáticas','abrochadoras-neumaticas','construccion','abrochadoras','https://ebtools.com.ar/wp-content/uploads/2021/02/93.-1024x1024.jpg','Alta velocidad para obra continua.','Abrochadoras neumáticas de cuerpo ligero y disparo secuencial o simple. Perfectas para armado de pallets, marcos de madera y estructuras livianas en obra. Alimentadas por aire comprimido, eliminan la fatiga del operario en jornadas intensivas.',4,true);
insert into products(id,name,slug,cat,subcat,img,short,descr,sort,active) values(5,'Clipeadoras Manual y Neumática','clipeadoras-manual-neumatica','gastronomia','embutidos','https://ebtools.com.ar/wp-content/uploads/2022/03/WhatsApp-Image-2022-03-22-at-14.05.06-3-1024x1024.jpeg','Cierre profesional de embutidos.','Clipeadoras para sellado de tripas en producción de embutidos. El modelo manual es ideal para producciones artesanales, mientras que el neumático multiplica la velocidad en líneas industriales. Utilizan clips de aluminio estándar de alta retención.',5,true);
insert into products(id,name,slug,cat,subcat,img,short,descr,sort,active) values(6,'Pinza Abrochadora para Tripa','pinza-abrochadora-tripa','gastronomia','embutidos','https://ebtools.com.ar/wp-content/uploads/2017/07/116-1024x1024.jpg','Para salamines y chorizos.','Pinza manual diseñada para el amarre y cierre de tripas de salamín, salchicha y chorizo. Construcción en acero inoxidable apto para uso alimentario. Ergonómica y de bajo mantenimiento para carnicerías y fábricas de embutidos.',6,true);
insert into products(id,name,slug,cat,subcat,img,short,descr,sort,active) values(7,'Cortadora de Papas Bastón','cortadora-papas-baston','gastronomia','corte-procesado','https://ebtools.com.ar/wp-content/uploads/2025/12/WhatsApp_Image_2025-10-31_at_11.08.32-removebg-preview-4.png','3 tipos de corte. Acero inox.','Cortadora gastronómica de palancas para papas fritas estilo bastón. Incluye 3 rejas de corte intercambiables (6mm, 8mm y 10mm). Cuerpo de acero inoxidable, fácil desmontaje para limpieza. Ideal para restaurantes y franquicias de comida rápida.',7,true);
insert into products(id,name,slug,cat,subcat,img,short,descr,sort,active) values(8,'Embutidora Manual Horizontal 3L','embutidora-manual-horizontal-3l','gastronomia','embutidos','https://ebtools.com.ar/wp-content/uploads/2025/12/WhatsApp-Image-2025-12-03-at-11.59.47.jpeg','Producción artesanal de embutidos.','Embutidora horizontal de 3 litros con cilindro de acero inoxidable y sistema de palanca de dos velocidades. Permite un llenado uniforme y sin aire para salchichas, chorizos y morcillas. Incluye boquillas de 16, 22 y 32mm.',8,true);
insert into products(id,name,slug,cat,subcat,img,short,descr,sort,active) values(9,'Multiprocesadora Industrial 5 Discos','multiprocesadora-industrial-5-discos','gastronomia','corte-procesado','https://ebtools.com.ar/wp-content/uploads/2025/12/WhatsApp-Image-2025-12-03-at-12.32.41-1024x725.jpeg','Corte, rallado y laminado en segundos.','Procesadora de alimentos de uso profesional con 5 discos intercambiables: rallador, laminador, cortador en juliana, cortador fino y rebanador. Motor de alta potencia, recipiente de 5L. Para restaurantes, hoteles y cocinas industriales.',9,true);
insert into products(id,name,slug,cat,subcat,img,short,descr,sort,active) values(10,'Embutidoras Manual y Eléctrica','embutidoras-manual-electrica','gastronomia','embutidos','https://ebtools.com.ar/wp-content/uploads/2025/03/3-y-5L-1024x1024.jpg','3 y 5 litros. Inox alimentario.','Línea completa de embutidoras en capacidades de 3 y 5 litros, disponibles en versión manual y eléctrica. Construcción en acero inoxidable 304 apto para industria alimentaria. La versión eléctrica incorpora motor de 180W con selector de velocidad.',10,true);
insert into products(id,name,slug,cat,subcat,img,short,descr,sort,active) values(11,'Atadora de Embutidos Manual','atadora-embutidos-manual','gastronomia','embutidos','https://ebtools.com.ar/wp-content/uploads/2022/08/Atadora-Chorizos-1024x1024.jpg','Atado uniforme a alta velocidad.','Máquina atadora manual para embutidos tipo salchicha y chorizo. Realiza el atado con hilo automáticamente, logrando porciones uniformes sin necesidad de anudar a mano. Compacta y de fácil ajuste para distintos diámetros de tripa.',11,true);
insert into products(id,name,slug,cat,subcat,img,short,descr,sort,active) values(12,'Cortadora de Fiambre Eléctrica','cortadora-fiambre-electrica','gastronomia','corte-procesado','https://ebtools.com.ar/wp-content/uploads/2025/12/WhatsApp-Image-2025-12-03-at-11.14.45-3.jpeg','Disco 300mm. Espesor regulable.','Cortadora eléctrica de fiambres y quesos con disco de acero inoxidable de 300mm. Corte regulable de 0 a 15mm de espesor. Bandeja de aluminio con guía antideslizante. Ideal para delis, supermercados y cocinas profesionales.',12,true);
insert into products(id,name,slug,cat,subcat,img,short,descr,sort,active) values(13,'Picadora de Carne Eléctrica N32','picadora-carne-electrica-n32','gastronomia','corte-procesado','https://ebtools.com.ar/wp-content/uploads/2025/12/WhatsApp-Image-2025-11-03-at-13.30.07.jpeg','Alta producción. Tornillo N°32.','Picadora eléctrica de carne con cabezal N°32 y motor de alta potencia para producción continua. Incluye discos de 3mm, 6mm y 8mm. Cuerpo de aluminio fundido con acabado resistente a impactos. Producción estimada: 80-120kg/h.',13,true);
insert into products(id,name,slug,cat,subcat,img,short,descr,sort,active) values(14,'Clipeadora para Bolsas y Redes','clipeadora-bolsas-redes','gastronomia','embutidos','https://ebtools.com.ar/wp-content/uploads/2025/12/Sin-titulo-1-1024x1024.jpg','Sellado de bolsas y redes de malla.','Clipeadora específicamente diseñada para el cierre de bolsas de polietileno y redes de malla usadas en packaging de carnes, frutas y verduras. Neumática o manual, aplica clip metálico estándar con un solo golpe. Producción: hasta 40 clips/min.',14,true);
insert into products(id,name,slug,cat,subcat,img,short,descr,sort,active) values(15,'Tijeras de Poda','tijeras-poda','agro','poda','https://ebtools.com.ar/wp-content/uploads/2021/01/4a-1024x1024.jpg','Para viña, frutales y horticultura.','Tijeras de poda con cuerpo de aluminio aeronáutico y hojas de acero SK5 endurecido. Diseño bypass de apertura regulable para adaptarse a distintos tamaños de mano. Disponibles en modelos manuales y neumáticos. Peso: 280g.',15,true);
insert into products(id,name,slug,cat,subcat,img,short,descr,sort,active) values(16,'Atadoras Tutoreadoras','atadoras-tutoreadoras','agro','atado-injerto','https://ebtools.com.ar/wp-content/uploads/2020/12/33-1024x1024.jpg','Para viñas, tomates y espárragos.','Máquina atadora para sujeción de plantas a tutores y espalderas. Utiliza cinta de nylon y grapa metálica en un movimiento simultáneo. Multiplica por 10 la velocidad respecto al atado manual. Compatible con cintas de 0.06mm de grosor.',16,true);
insert into products(id,name,slug,cat,subcat,img,short,descr,sort,active) values(17,'Tijera y Navaja para Injertos','tijera-navaja-injertos','agro','atado-injerto','https://ebtools.com.ar/wp-content/uploads/2021/07/injertos-1024x1024.jpg','Cortes de injerto en omega y lengüeta.','Kit de herramientas para injertos de precisión que incluye tijera con cuchillas intercambiables para cortes en omega, lengüeta y recto, más navaja de injerto con hoja de carbono. Para viticultores y viveristas profesionales.',17,true);
insert into products(id,name,slug,cat,subcat,img,short,descr,sort,active) values(18,'Serruchos de Poda','serruchos-poda','agro','poda','https://ebtools.com.ar/wp-content/uploads/2021/02/serrucho-1-1024x1024.jpg','Corte limpio en ramas de hasta 80mm.','Serruchos de poda con hoja curva de 30cm en acero de alto carbono con triple filo. El diseño curvo maximiza el corte en el movimiento de tracción. Mango ergonómico con grip antideslizante. Para ramas de hasta 80mm de diámetro.',18,true);
insert into products(id,name,slug,cat,subcat,img,short,descr,sort,active) values(19,'Pértigas Extensibles','pertigas-extensibles','agro','poda','https://ebtools.com.ar/wp-content/uploads/2022/03/palo3-1024x1024.jpg','Aluminio. Hasta 4 metros de largo.','Pértigas telescópicas de aluminio de alta resistencia para acople de herramientas de altura. Extensibles desde 1.5m hasta 4m. Sistema de bloqueo por tuerca que mantiene la longitud con total seguridad durante el trabajo.',19,true);
insert into products(id,name,slug,cat,subcat,img,short,descr,sort,active) values(20,'Tijera Poda Extensible en Altura','tijera-poda-extensible-altura','agro','poda','https://ebtools.com.ar/wp-content/uploads/2022/08/WhatsApp-Image-2022-06-01-at-10.08.33-AM-1.jpeg','Poda y cosecha desde el suelo.','Tijera de poda telescópica que combina la funcionalidad de una tijera profesional con un palo extensible. Permite podar y cosechar en alturas de hasta 3.5m sin escalera. Accionamiento por cable de acero con gatillo ergonómico.',20,true);
insert into products(id,name,slug,cat,subcat,img,short,descr,sort,active) values(21,'Llave de Impacto Neumática','llave-impacto-neumatica','neumaticas','impacto','https://ebtools.com.ar/wp-content/uploads/2021/02/2-1-1024x1024.jpg','Torque: 680 Nm. Cuadro 1/2".','Pistola de impacto neumática de cuadro 1/2" con torque máximo de 680 Nm. Mecanismo de doble martillo para mayor durabilidad. Consumo de aire: 140 l/min a 6.3 bar. Ideal para mecánica automotriz, talleres y mantenimiento industrial.',21,true);
insert into products(id,name,slug,cat,subcat,img,short,descr,sort,active) values(22,'Grasera Engrasadora Neumática','grasera-engrasadora-neumatica','neumaticas','varios-neumaticos','https://ebtools.com.ar/wp-content/uploads/2021/02/grasera7-1024x1024.jpg','Neumática y manual. 400cm³.','Engrasadora de doble uso: neumática (accionada por compresor) y manual (palanca). Capacidad de cartucho 400cm³. Presión máxima: 700 bar. Manguera de 1.2m con boquilla giratoria. Para engrase de rodamientos, articulaciones y maquinaria agrícola.',22,true);
insert into products(id,name,slug,cat,subcat,img,short,descr,sort,active) values(23,'Kit Aire Comprimido Completo','kit-aire-comprimido','neumaticas','varios-neumaticos','https://ebtools.com.ar/wp-content/uploads/2021/01/kit-completo-1-1024x1024.jpg','Pistola, manguera y acoples.','Kit completo para conexión de herramientas neumáticas que incluye pistola sopladora, pico inflador, manómetro digital, acople rápido macho/hembra y manguera de 5m. Todo lo necesario para poner en marcha un compresor.',23,true);
insert into products(id,name,slug,cat,subcat,img,short,descr,sort,active) values(24,'Martillo Demoledor Neumático','martillo-demoledor-neumatico','neumaticas','varios-neumaticos','https://ebtools.com.ar/wp-content/uploads/2021/03/martillon-1024x1024.jpg','2500 golpes/min. Para hormigón.','Martillo demoledor neumático de alta percusión para demolición de hormigón, extracción de azulejos y ruptura de pavimento. 2500 golpes/minuto. Vástago hexagonal de 28mm. Incluye cincel plano, cincel punta y escarpe.',24,true);
insert into products(id,name,slug,cat,subcat,img,short,descr,sort,active) values(25,'Amoladora Recta Neumática','amoladora-recta-neumatica','neumaticas','abrasivos','https://ebtools.com.ar/wp-content/uploads/2021/02/amoladora2-1024x1024.jpg','25.000 RPM. Para piezas interiores.','Amoladora recta neumática de alta velocidad (25.000 RPM) para desbaste y pulido en orificios, moldes y piezas de geometría compleja. Collet de 6mm, consumo de 140 l/min. Cuerpo delgado para acceso en espacios reducidos.',25,true);
insert into products(id,name,slug,cat,subcat,img,short,descr,sort,active) values(26,'Remachadora Pop Neumática','remachadora-pop-neumatica','neumaticas','varios-neumaticos','https://ebtools.com.ar/wp-content/uploads/2021/02/Remachadora-1024x1024.jpg','Hasta 800 remaches/hora.','Remachadora neumática para remaches pop de aluminio y acero en diámetros 3.2, 4, 4.8 y 6.4mm. Ciclo completo automático (remache y extracción de mandril). Producción de hasta 800 remaches/hora. Para estructuras, chapa y carpintería metálica.',26,true);
insert into products(id,name,slug,cat,subcat,img,short,descr,sort,active) values(27,'Pistolas para Sopletear','pistolas-sopletear','neumaticas','varios-neumaticos','https://ebtools.com.ar/wp-content/uploads/2021/01/kit2-1024x1024.jpg','Limpieza por soplado de alta potencia.','Pistolas de soplado neumático con cañón de acero y válvula de gatillo regulable. Para limpieza de virutas, polvo y humedad en maquinaria, circuitos electrónicos y superficies de trabajo. Presión regulable 0-8 bar.',27,true);
insert into products(id,name,slug,cat,subcat,img,short,descr,sort,active) values(28,'Amoladora Cortadora Neumática','amoladora-cortadora-neumatica','neumaticas','abrasivos','https://ebtools.com.ar/wp-content/uploads/2021/02/amoladora2-2-1024x1024.jpg','Disco 115mm. 10.000 RPM.','Amoladora angular neumática para disco de corte de 115mm (4.5"). Velocidad libre: 10.000 RPM. Consumo: 170 l/min. Cuerpo de aluminio con empuñadura lateral orientable. Para corte de metales, tuberías y estructuras.',28,true);
insert into products(id,name,slug,cat,subcat,img,short,descr,sort,active) values(29,'Llave Impacto Camión Profesional','llave-impacto-camion-profesional','neumaticas','impacto','https://ebtools.com.ar/wp-content/uploads/2021/09/LLIC-3-1024x1024.jpg','1" cuadro. 2700 Nm máximo.','Llave de impacto de cuadro 1" para servicio pesado en camiones, maquinaria agrícola y equipos de construcción. Torque máximo: 2700 Nm. Triple martillo para mayor eficiencia. Consumo de aire: 600 l/min a 6.2 bar.',29,true);
insert into products(id,name,slug,cat,subcat,img,short,descr,sort,active) values(30,'Lijadora Orbital Neumática 150mm','lijadora-orbital-neumatica-150mm','neumaticas','abrasivos','https://ebtools.com.ar/wp-content/uploads/2022/08/Lijadora2-1024x1024.jpg','Base 150mm. 12.000 OPM.','Lijadora roto-orbital neumática con base de 150mm (6") y velocidad de 12.000 OPM. Sistema de fijación de lija por velcro. Extracción de polvo por orificio central. Para acabados en carrocería, madera y fibra de vidrio.',30,true);
insert into products(id,name,slug,cat,subcat,img,short,descr,sort,active) values(31,'Pistola Soplete para Arenar','pistola-soplete-arenar','sopletes','arenado','https://ebtools.com.ar/wp-content/uploads/2021/02/PistolaArena-copy-1024x1024.jpg','Arenado por succión y presión.','Pistola de arenado neumático por succión para limpieza de óxido, pintura y contaminantes superficiales. Boquilla de carburo de boro de larga duración. Compatible con arena silícea, granalla y microesferas. Para preparación de superficies metálicas.',31,true);
insert into products(id,name,slug,cat,subcat,img,short,descr,sort,active) values(32,'Pistola Pintura por Succión','pistola-pintura-succion','sopletes','pintura','https://ebtools.com.ar/wp-content/uploads/2021/02/PistolaAire1-1-1024x1024.jpg','Vaso inferior 600ml. HVLP.','Pistola soplete de pintura por succión con vaso de aluminio de 600ml. Sistema HVLP (alto volumen, baja presión) para mejor transfer y menor desperdicio de material. Boquilla regulable de 1.5 y 1.8mm. Para lacas, esmaltes y fondos.',32,true);
insert into products(id,name,slug,cat,subcat,img,short,descr,sort,active) values(33,'Pistola Soplete por Gravedad','pistola-soplete-gravedad','sopletes','pintura','https://ebtools.com.ar/wp-content/uploads/2021/07/pistolavaso1-1024x1024.jpg','Vaso superior 600ml. Alta atomización.','Pistola de pintura por gravedad con vaso superior de aluminio de 600ml. Alta atomización para acabados de primera calidad en carrocería y carpintería. Aguja de acero inoxidable, cabezal de aluminio mecanizado. Boquilla 1.4mm incluida.',33,true);
insert into products(id,name,slug,cat,subcat,img,short,descr,sort,active) values(34,'Pistola Pintura Tolva 5L','pistola-pintura-tolva-5l','sopletes','pintura','https://ebtools.com.ar/wp-content/uploads/2021/03/Pistola-Pintar-Aluminio1-1-1024x1024.jpg','Para grandes superficies. 5 litros.','Pistola tolva de gran capacidad (5 litros) para aplicación de pintura en paredes, cielos rasos y grandes superficies industriales. Reduce la cantidad de recargas y aumenta la productividad. Compatible con pintura látex, epoxi y caucho clorado.',34,true);
insert into products(id,name,slug,cat,subcat,img,short,descr,sort,active) values(35,'Unidad Filtro Compresor','unidad-filtro-compresor','filtros','filtros-unidades','https://ebtools.com.ar/wp-content/uploads/2021/02/FilrtoAire1-1024x1024.jpg','Filtrado y regulación en un cuerpo.','Unidad de mantenimiento de aire comprimido que integra filtro de partículas, regulador de presión y manómetro en un solo cuerpo. Conexión 1/4" NPT. Vaso de policarbonato desmontable para limpieza. Para todo tipo de herramientas neumáticas.',35,true);
insert into products(id,name,slug,cat,subcat,img,short,descr,sort,active) values(36,'Manómetro Medidor de Presión','manometro-medidor-presion','filtros','medicion','https://ebtools.com.ar/wp-content/uploads/2022/03/M2-1024x1024.jpg','0 a 16 bar. Esfera 63mm.','Manómetro de bourdon para medir presión de aire en sistemas neumáticos. Escala dual bar/PSI de 0-16 bar. Cuerpo de acero con esfera de glicerina para amortiguación de golpes. Conexión inferior 1/4" BSP. Para montaje en línea o panel.',36,true);
insert into products(id,name,slug,cat,subcat,img,short,descr,sort,active) values(37,'Filtro Trampa de Agua','filtro-trampa-agua','filtros','filtros-unidades','https://ebtools.com.ar/wp-content/uploads/2021/02/filtro-1024x1024.jpg','Retiene humedad y partículas.','Filtro separador de agua y aceite para líneas de aire comprimido. Vaso de policarbonato transparente con drenaje automático. Conexión 1/4" NPT. Esencial para proteger herramientas neumáticas y asegurar calidad en aplicaciones de pintura.',37,true);
insert into products(id,name,slug,cat,subcat,img,short,descr,sort,active) values(38,'Mini Lubricador','mini-lubricador','filtros','filtros-unidades','https://ebtools.com.ar/wp-content/uploads/2021/07/WhatsApp-Image-2021-04-28-at-11.10.09-AM.jpeg','Dosificación de aceite en línea.','Lubricador de línea neumática que incorpora aceite en neblina al flujo de aire, lubricando automáticamente todas las herramientas conectadas. Depósito de 30ml, ajuste de dosificación por tornillo exterior. Conexión 1/4" NPT.',38,true);
insert into products(id,name,slug,cat,subcat,img,short,descr,sort,active) values(39,'Acoples Rápidos','acoples-rapidos','filtros','acoples','https://ebtools.com.ar/wp-content/uploads/2021/07/acoples-1024x1024.jpg','Conexión y desconexión en un movimiento.','Acoples rápidos de acero pavonado para conexión/desconexión sin herramientas de mangueras y herramientas neumáticas. Disponibles en tapones y enchufes tipo ARO (industrial). Presión máxima: 16 bar. Pares macho/hembra.',39,true);
insert into products(id,name,slug,cat,subcat,img,short,descr,sort,active) values(40,'Pico para Inflar','pico-para-inflar','filtros','acoples','https://ebtools.com.ar/wp-content/uploads/2022/08/Pico-inflador-1024x1024.jpg','Válvula Schrader y aguja de pelota.','Pico inflador para válvulas Schrader (neumáticos) y aguja para pelotas. Cuerpo de latón con cierre de goma. Conexión a manguera o pistola de aire. Para gomería, bicicleterías y uso general.',40,true);
insert into products(id,name,slug,cat,subcat,img,short,descr,sort,active) values(41,'Presostato 380V','presostato-380v','repuestos','presostatos','https://ebtools.com.ar/wp-content/uploads/2021/09/Preso-4-380-1024x1024.jpg','Trifásico. 4 salidas. Hasta 12 bar.','Presostato trifásico 380V para control automático de compresores industriales. 4 salidas de aire + purga automática. Rango de presión regulable 6-12 bar. Terminales de 40A. Apto para compresores de 5HP a 15HP en instalaciones trifásicas.',41,true);
insert into products(id,name,slug,cat,subcat,img,short,descr,sort,active) values(42,'Regulador Caudal Aire 1/4"','regulador-caudal-aire','repuestos','reguladores','https://ebtools.com.ar/wp-content/uploads/2022/03/RR1-1024x1024.jpg','Ajuste preciso de presión de salida.','Regulador de presión de aire con manómetro incorporado para ajuste fino de la presión de trabajo. Conexión 1/4" NPT entrada/salida. Rango 0.5-10 bar. Cuerpo de aluminio con perilla de bloqueo. Para herramientas neumáticas de precisión.',42,true);
insert into products(id,name,slug,cat,subcat,img,short,descr,sort,active) values(43,'Válvulas Anti Retorno','valvulas-anti-retorno','repuestos','valvulas','https://ebtools.com.ar/wp-content/uploads/2022/08/WhatsApp-Image-2022-05-16-at-16.25.46-1-1024x1024.jpeg','Previene el retorno de flujo.','Válvulas de retención (check valves) para instalaciones de aire comprimido. Evitan el retorno de aire hacia el compresor al detener la máquina. Cuerpo de latón, disponibles en 1/4", 3/8" y 1/2" BSP. Presión máxima: 16 bar.',43,true);
insert into products(id,name,slug,cat,subcat,img,short,descr,sort,active) values(44,'Regulador de Aire Compresor','regulador-aire-compresor','repuestos','reguladores','https://ebtools.com.ar/wp-content/uploads/2022/08/R-1024x1024.jpg','Sin manómetro. Para panel o línea.','Regulador de presión de cuerpo compacto para instalación en panel o directamente en la salida del compresor. Sin manómetro (para usar con manómetro externo). Conexión 1/4" NPT. Regulación continua 0-10 bar.',44,true);
insert into products(id,name,slug,cat,subcat,img,short,descr,sort,active) values(45,'Manómetro','manometro','repuestos','reguladores','https://ebtools.com.ar/wp-content/uploads/2024/01/Manometro-solo-1024x1024.jpg','Conexión trasera. 10 bar.','Manómetro de repuesto para compresores y unidades de mantenimiento. Escala 0-10 bar, conexión trasera 1/8" BSP. Esfera de 40mm con indicador rojo de presión máxima. Compatible con la mayoría de compresores del mercado.',45,true);
insert into products(id,name,slug,cat,subcat,img,short,descr,sort,active) values(46,'Presostato 220V','presostato-220v','repuestos','presostatos','https://ebtools.com.ar/wp-content/uploads/2021/02/Persostato4-2-1024x1024.jpg','Monofásico. Purga automática.','Presostato monofásico 220V para compresores domésticos e industriales de hasta 10HP. 4 salidas de 1/4" + purga automática de condensado. Rango ajustable 6-10 bar. Terminales de 20A protegidos. Reemplaza presostatos de la mayoría de marcas.',46,true);
insert into products(id,name,slug,cat,subcat,img,short,descr,sort,active) values(47,'Base Presostato con Regulador','base-presostato-regulador','repuestos','presostatos','https://ebtools.com.ar/wp-content/uploads/2022/03/BP2-1024x1024.jpg','Presostato + regulador integrado.','Base multipunto que integra presostato, regulador de presión con manómetro y múltiples salidas de 1/4". Simplifica la instalación al concentrar en un solo componente el control y distribución del aire comprimido. Para compresores 220V.',47,true);
insert into products(id,name,slug,cat,subcat,img,short,descr,sort,active) values(48,'Válvula de Seguridad Calibrada','valvula-seguridad-calibrada','repuestos','valvulas','https://ebtools.com.ar/wp-content/uploads/2022/08/V5-1024x1024.jpg','Calibrada en fábrica a 8, 10 o 12 bar.','Válvulas de seguridad (alivio) calibradas de fábrica para distintas presiones: 8, 10 y 12 bar. Conexión 1/4" BSP. Cuerpo de latón cromado. Obligatoria en toda instalación de compresor según normativa de recipientes a presión.',48,true);
insert into products(id,name,slug,cat,subcat,img,short,descr,sort,active) values(49,'Válvula de Salida Aire','valvula-salida-aire','repuestos','valvulas','https://ebtools.com.ar/wp-content/uploads/2022/08/V2-1024x1024.jpg','Llave de paso 1/4" para compresor.','Válvula de esfera de paso total para salida de aire de compresores. Cuerpo de latón con palanca de accionamiento rápido. Conexión 1/4" BSP. Para instalación directa en la salida del tanque o en manifold de distribución.',49,true);
insert into products(id,name,slug,cat,subcat,img,short,descr,sort,active) values(50,'Mangueras Espiraladas','mangueras-espiraladas','mangueras','mangueras-tipos','https://ebtools.com.ar/wp-content/uploads/2021/02/manguera3-1024x1024.jpg','Retráctil. 10m extendida. 1/4".','Mangueras espiraladas (retráctiles) de poliuretano para herramientas neumáticas. Se extienden hasta 10m y vuelven a su longitud original (2m). Acoples de 1/4" macho en ambos extremos. Evitan enredos y tropiezos en el área de trabajo.',50,true);
insert into products(id,name,slug,cat,subcat,img,short,descr,sort,active) values(51,'Manguera PVC Alta Presión','manguera-pvc-alta-presion','mangueras','mangueras-tipos','https://ebtools.com.ar/wp-content/uploads/2021/02/56-1024x1024.jpg','Hasta 20 bar. Reforzada 3 trenzas.','Manguera de PVC plastificado con triple refuerzo de trenzado de poliéster. Presión de trabajo: 20 bar. Presión de rotura: 60 bar. Diámetro interior 6mm (1/4"). Disponible en bobinas de 25 y 50 metros o cortada a medida.',51,true);
insert into products(id,name,slug,cat,subcat,img,short,descr,sort,active) values(52,'Pico Inflador con Manómetro','pico-inflador-manometro','mangueras','infladores','https://ebtools.com.ar/wp-content/uploads/2021/01/kit4-1024x1024.jpg','Inflado controlado con lectura directa.','Pico inflador con manómetro incorporado para inflado preciso de neumáticos de autos, motos y camiones. Escala dual bar/PSI. Permite inflar y desinflar con control visual permanente de la presión. Válvula Schrader universal.',52,true);
insert into products(id,name,slug,cat,subcat,img,short,descr,sort,active) values(53,'Manómetro para Neumáticos','manometro-neumaticos','mangueras','infladores','https://ebtools.com.ar/wp-content/uploads/2022/03/M-1024x1024.jpg','Lápiz de presión digital. 0-60 PSI.','Medidor de presión de neumáticos en formato lápiz. Escala 0-60 PSI / 0-4 bar. Lectura digital inmediata. Cuerpo de aluminio anodizado con funda de goma protectora. Imprescindible en gomería, automotores y vehículos de trabajo.',53,true);
