-- ===== EBTOOLS — ESQUEMA SUPABASE =====
-- Ejecutar en: Supabase -> SQL Editor -> New query -> Run
-- Crea tablas, políticas RLS y carga los datos iniciales (53 productos).

-- ---------- TABLAS ----------
create table if not exists categories (
  key   text primary key,
  label text not null,
  icon  text,
  sort  int  not null default 0
);

create table if not exists subcategories (
  key   text primary key,
  cat   text not null references categories(key) on delete cascade,
  label text not null,
  sort  int  not null default 0
);

create table if not exists products (
  id     bigint generated by default as identity primary key,
  name   text not null,
  slug   text,
  cat    text not null references categories(key) on delete restrict,
  subcat text references subcategories(key) on delete set null,
  img    text,
  short  text,
  descr  text,
  sort   int  not null default 0,
  active boolean not null default true,
  created_at timestamptz not null default now()
);

create index if not exists products_cat_idx    on products(cat);
create index if not exists products_subcat_idx on products(subcat);

-- ---------- RLS ----------
alter table categories    enable row level security;
alter table subcategories enable row level security;
alter table products      enable row level security;

-- Lectura pública (anon + authenticated)
drop policy if exists "public read categories"    on categories;
drop policy if exists "public read subcategories" on subcategories;
drop policy if exists "public read products"      on products;
create policy "public read categories"    on categories    for select using (true);
create policy "public read subcategories" on subcategories for select using (true);
create policy "public read products"      on products      for select using (true);

-- Escritura solo para usuarios autenticados (el admin del backoffice)
drop policy if exists "auth write categories"    on categories;
drop policy if exists "auth write subcategories" on subcategories;
drop policy if exists "auth write products"      on products;
create policy "auth write categories"    on categories    for all to authenticated using (true) with check (true);
create policy "auth write subcategories" on subcategories for all to authenticated using (true) with check (true);
create policy "auth write products"      on products      for all to authenticated using (true) with check (true);

-- ---------- DATOS INICIALES ----------



-- Reset de la secuencia de id para que los nuevos productos sigan despues del 53
select setval(pg_get_serial_sequence('products','id'), (select max(id) from products));
